from dataclasses import dataclass, field
from typing import Optional
import asyncio


@dataclass
class Agent:
    name: str
    role: str
    capabilities: list[str]
    status: str = "idle"
    tasks_completed: int = 0


class MultiAgentSystem:
    def __init__(self):
        self.agents: dict[str, Agent] = {}
        self.task_queue: list[dict] = []
        self.results: dict[str, list] = {}

    def register_agent(self, agent: Agent):
        self.agents[agent.name] = agent
        print(f"Registered agent: {agent.name} ({agent.role})")

    def assign_task(self, task_name: str, required_capability: str) -> Optional[str]:
        """Assign task to an agent with matching capability."""
        for name, agent in self.agents.items():
            if (agent.status == "idle" and
                required_capability in agent.capabilities):
                agent.status = "working"
                print(f"Assigned '{task_name}' to {name}")
                return name
        print(f"No available agent for capability: {required_capability}")
        return None

    def complete_task(self, agent_name: str, task_name: str, result: str):
        """Mark task as complete and collect result."""
        if agent_name in self.agents:
            self.agents[agent_name].status = "idle"
            self.agents[agent_name].tasks_completed += 1
            if task_name not in self.results:
                self.results[task_name] = []
            self.results[task_name].append({
                "agent": agent_name,
                "result": result
            })
            print(f"{agent_name} completed '{task_name}'")

    def get_status(self) -> dict:
        """Get system status."""
        return {
            "agents": {
                name: {
                    "role": agent.role,
                    "status": agent.status,
                    "completed": agent.tasks_completed
                }
                for name, agent in self.agents.items()
            },
            "pending_tasks": len(self.task_queue),
            "completed_tasks": len(self.results)
        }


# Example: Research Team
system = MultiAgentSystem()

# Register agents
system.register_agent(Agent(
    name="researcher",
    role="Web Researcher",
    capabilities=["web_search", "data_collection"]
))

system.register_agent(Agent(
    name="analyst",
    role="Data Analyst",
    capabilities=["data_analysis", "statistics"]
))

system.register_agent(Agent(
    name="writer",
    role="Content Writer",
    capabilities=["writing", "editing"]
))

# Assign tasks
research_agent = system.assign_task("Gather AI news", "web_search")
analyst_agent = system.assign_task("Analyze trends", "data_analysis")
writer_agent = system.assign_task("Write report", "writing")

# Complete tasks
if research_agent:
    system.complete_task(research_agent, "Gather AI news", "Found 15 relevant articles")
if analyst_agent:
    system.complete_task(analyst_agent, "Analyze trends", "Identified 3 key trends")
if writer_agent:
    system.complete_task(writer_agent, "Write report", "Report drafted successfully")

# Get status
import json
print(json.dumps(system.get_status(), indent=2))
